const { S3Client, PutObjectCommand } = require('@aws-sdk/client-s3');
const { getSignedUrl } = require('@aws-sdk/s3-request-presigner');
const { randomUUID } = require('crypto');

const body = $input.first().json.body ?? {};
const patientId = $input.first().json.query?.patientId || body.patientId;
const { filename, contentType } = body;

if (!patientId || !filename || !contentType) {
  return [{ json: { success: false, error: 'patientId, filename, and contentType are required' } }];
}

const accountId = process.env.R2_ACCOUNT_ID;
const accessKeyId = process.env.R2_ACCESS_KEY_ID;
const secretAccessKey = process.env.R2_SECRET_ACCESS_KEY;
const bucket = process.env.R2_BUCKET_NAME;
const publicUrlBase = process.env.R2_PUBLIC_URL;

const s3 = new S3Client({
  region: 'auto',
  endpoint: `https://${accountId}.r2.cloudflarestorage.com`,
  credentials: { accessKeyId, secretAccessKey }
});

const r2Key = `patients/${patientId}/photos/${randomUUID()}-${filename}`;

const command = new PutObjectCommand({
  Bucket: bucket,
  Key: r2Key,
  ContentType: contentType
});

try {
  const uploadUrl = await getSignedUrl(s3, command, { expiresIn: 300 });
  const publicUrl = `${publicUrlBase}/${r2Key}`;
  return [{ json: { uploadUrl, r2Key, publicUrl } }];
} catch (err) {
  return [{ json: { success: false, error: `S3 Error: ${err.message}` } }];
}
